## 6. 实际使用示例

### 状态提取（state-extractor.ts）
```typescript
// 旧方式
const languageModel = await getNovelLanguageModel()
const result = await generateText({
  model: languageModel,
  prompt: buildStateExtractionPrompt(storyText, currentState),
})
const updates = JSON.parse(result.text.match(/\{[\s\S]*\}/)[0])

// 新方式
const result = await callLLMJson<StateUpdate>({
  prompt: buildStateExtractionPrompt(storyText, currentState),
  callType: "state_extraction",
  schemaDescription: "{ character_updates: [], relationships: {}, ... }",
  useRetry: true,
})
const updates = result.data  // 已解析，类型安全
```

### 分支生成（orchestrator.ts）
```typescript
// 旧方式
const languageModel = await getNovelLanguageModel()
const result = await generateText({
  model: languageModel,
  prompt: branchPrompt,
  temperature: 0.8,
})

// 新方式
const result = await callLLM({
  prompt: branchPrompt,
  callType: "branch_generation",
  temperature: 0.8,
  useRetry: true,
  retryConfig: new RetryConfig({ maxRetries: 2 }),
})
```

### 角色分析（pattern-miner-enhanced.ts）
```typescript
// 旧方式
const languageModel = await getNovelLanguageModel()
const result = await generateText({
  model: languageModel,
  prompt: archetypePrompt,
})
const jsonMatch = result.text.match(/\[[\s\S]*\]/)
const archetypes = JSON.parse(jsonMatch[0])

// 新方式
const result = await callLLMJson<Archetype[]>({
  prompt: archetypePrompt,
  callType: "archetype_extraction",
  schemaDescription: "[{ characterName, archetypeType, description, ... }]",
})
const archetypes = result.data  // 直接可用
```

### 批量角色深度分析
```typescript
// 需要分析多个角色
const characters = ["Alice", "Bob", "Charlie"]
const calls = characters.map(name => ({
  prompt: `Deep analyze character: ${name}`,
  callType: "character_deepening",
  temperature: 0.5,
}))

const results = await callLLMBatch(calls, concurrency: 3)

for (let i = 0; i < results.length; i++) {
  const character = characters[i]
  const analysis = results[i].text
  console.log(`${character}: ${analysis}`)
}
```

